  ambessa: { diff: "EVEN", tone: "#e8b84b", tldr: "Out-sustain her \u2014 R-lock her when her dashes are down.", breakdown: "Q-bite to out-sustain, bait her dashes, and R-lock her when her mobility is down.", dos: ["Q-bite to out-sustain", "Bait her dashes", "R-lock when her dashes are down"], donts: ["Trade into her full combo", "Chase her dashes", "Fight low with no R"], key: { slot: "E", name: "Repeating Dashes", cd: "12s", note: "Her mobility. R-lock when it\u2019s down.", winT: "DASHES DOWN", winS: "Q-bite + R her." }, hold: "Hold R until her dashes are down \u2014 she dashes out of the suppress otherwise.", tip: "Out-sustain her combo, then R-lock her when her mobility is spent \u2014 she can\u2019t dash out.", win: "Out-sustain her and R-lock her." },
