  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — out-sustain him and fear his Heroic Swing commitment.","breakdown":"Akshan plays around Heroic Swing. Q-bite heals through his chip, E-fear flips his Heroic Swing all-in, and below half HP your W attack speed takes over. Doran’s Shield blunts the poke war.","dos":["Q-bite to out-sustain trades","E-fear his Heroic Swing commit","R the kill window"],"donts":["Trade into his Heroic Swing","Burn E before his engage","Waste R into peel"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Q-bite, E-fear, out-sustain."},"win":"Out-sustain him and fear his Heroic Swing commitment."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then out-sustain him and fear his Miasma commitment.","breakdown":"Cassiopeia plays around Miasma. Q-bite heals through his chip, E-fear flips his Miasma all-in, and below half HP your W attack speed takes over. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Q-bite to out-sustain trades","E-fear his Miasma commit","R the kill window"],"donts":["Trade into his Miasma","Burn E before his engage","Waste R into peel"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Q-bite, E-fear, out-sustain."},"win":"Out-sustain him and fear his Miasma commitment."},
